echo "{\"os\":\"$(grep PRETTY_NAME /etc/os-release | cut -d'"' -f2)\",\"kernel\":\"$(uname -r)\",\"arch\":\"$(uname -m)\",\"cpu\":\"$(lscpu | grep 'Model name' | cut -d':' -f2 | xargs)\",\"cores\":$(lscpu -p | grep -v '^#' | sort -u -t, -k 2 | wc -l),\"threads\":$(nproc),\"ram\":\"$(free -h | awk '/^Mem:/ {print $2}')\",\"ram_speed\":\"$(sudo dmidecode -t memory 2>/dev/null | awk '/Speed: [0-9]+ MHz/{print $2; exit}')\",\"motherboard\":\"$(cat /sys/class/dmi/id/board_vendor 2>/dev/null) $(cat /sys/class/dmi/id/board_name 2>/dev/null)\",\"gpu\":\"$(lspci | grep -i vga | sed 's/^.*: //' | xargs)\"}"
